import loginForm from './components/login-form/loginForm';
var PuzzleGame = /** @class */ (function () {
    function PuzzleGame(game) {
        this.game = game;
    }
    PuzzleGame.prototype.render = function (root) {
        if (root !== null) {
            root.append(this.game.getNode());
        }
        else {
            throw Error("Cannot render. Root is = ".concat(root));
        }
    };
    return PuzzleGame;
}());
var body = document.querySelector('body');
var game = new PuzzleGame(loginForm);
game.render(body);
